    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_successMessage
            <button type="button" class="btn-close" @onclick="() => _successMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-7">
            <!-- Theme -->
            <div class="card mb-3">
                <div class="card-body">
                    <h6 class="card-title">Theme</h6>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check form-check-inline">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <!-- Font Size -->
            <div class="card mb-3">
                <div class="card-body">
                    <h6 class="card-title">Font Size</h6>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check form-check-inline">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>
            </div>

            <!-- Language -->
            <div class="card mb-3">
                <div class="card-body">
                    <h6 class="card-title">Language</h6>
                    <select class="form-select" @bind="_language">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>
            </div>

            <!-- Compact Mode -->
            <div class="card mb-3">
                <div class="card-body">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                        <label class="form-check-label" for="compactMode">
                            <strong>Compact Mode</strong>
                            <br /><small class="text-muted">Reduce spacing and padding throughout the UI</small>
                        </label>
                    </div>
                </div>
            </div>
        </div>

        <!-- Live Preview -->
        <div class="col-md-5">
            <div class="card h-100">
                <div class="card-header">
                    <h6 class="mb-0">Live Preview</h6>
                </div>
                <div class="card-body preview-area @GetPreviewClasses()">
                    <div class="preview-header mb-2">
                        <strong>Dashboard</strong>
                    </div>
                    <p class="preview-text">
                        This is a preview of how your content will appear with the selected settings.
                    </p>
                    <div class="d-flex gap-2 mb-2">
                        <span class="badge bg-primary">Label</span>
                        <span class="badge bg-success">Active</span>
                    </div>
                    <button class="btn btn-sm btn-outline-primary">Sample Button</button>
                </div>
            </div>
        </div>
    </div>

    <button class="btn btn-primary mt-3" @onclick="SaveAsync" disabled="@_saving">
        @if (_saving)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
        }
        Save
    </button>
</div>

@code {
    [Parameter, EditorRequired]
    public AppearanceSettings Appearance { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _saving;
    private string? _successMessage;

    private static readonly string[] _languages = { "English", "Spanish", "French", "German", "Japanese", "Chinese" };

    protected override void OnParametersSet()
    {
        if (!_saving)
        {
            _theme = Appearance.Theme;
            _fontSize = Appearance.FontSize;
            _language = Appearance.Language;
            _compactMode = Appearance.CompactMode;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();

        classes.Add(_theme switch
        {
            "Dark" => "preview-dark",
            _ => "preview-light"
        });

        classes.Add(_fontSize switch
        {
            "Small" => "preview-font-sm",
            "Large" => "preview-font-lg",
            _ => "preview-font-md"
        });

        if (_compactMode)
            classes.Add("preview-compact");

        return string.Join(" ", classes);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        try
        {
            var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await OnSave.InvokeAsync(updated);
            _successMessage = "Appearance settings saved!";
        }
        finally
        {
            _saving = false;
        }
    }
}
