@using sv_40aab3eedb054e658e23431d84c78f5a.Models

<div class="security-section">
    <h4 class="mb-4">Security Settings</h4>

    @if (!string.IsNullOrEmpty(_statusMessage))
    {
        <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <!-- Change Password Panel -->
    <div class="card mb-4">
        <div class="card-header d-flex align-items-center justify-content-between"
             style="cursor: pointer" @onclick="() => _passwordExpanded = !_passwordExpanded">
            <h6 class="mb-0">Change Password</h6>
            <i class="bi @(_passwordExpanded ? "bi-chevron-up" : "bi-chevron-down")"></i>
        </div>
        @if (_passwordExpanded)
        {
            <div class="card-body">
                <div class="mb-3">
                    <label class="form-label">Current Password</label>
                    <input type="password" class="form-control" @bind="_currentPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">New Password</label>
                    <input type="password" class="form-control" @bind="_newPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Confirm New Password</label>
                    <input type="password" class="form-control" @bind="_confirmPassword" />
                </div>
                <button class="btn btn-warning" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                    @if (_changingPassword)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Update Password
                </button>
            </div>
        }
    </div>

    <!-- Two-Factor Authentication -->
    <div class="card mb-4">
        <div class="card-body">
            <div class="d-flex align-items-center justify-content-between">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <span class="badge @(Security.TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(Security.TwoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" checked="@Security.TwoFactorEnabled"
                           disabled
                           title="Contact your administrator to change 2FA settings" />
                </div>
            </div>
            @if (Security.LastPasswordChange.HasValue)
            {
                <small class="text-muted mt-2 d-block">
                    Last password change: @Security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </small>
            }
        </div>
    </div>

    <!-- Active Sessions -->
    <div class="card mb-4">
        <div class="card-header">
            <h6 class="mb-0">Active Sessions</h6>
        </div>
        <div class="card-body p-0">
            <div class="table-responsive">
                <table class="table table-hover mb-0">
                    <thead class="table-light">
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th class="text-end">Action</th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in Security.Sessions)
                        {
                            var isCurrent = session.Id == Security.Sessions.FirstOrDefault()?.Id;
                            <tr>
                                <td>
                                    @session.Device
                                    @if (isCurrent)
                                    {
                                        <span class="badge bg-primary ms-1">Current</span>
                                    }
                                </td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td class="text-end">
                                    @if (!isCurrent)
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>
    </div>

    <!-- Revoke Confirmation Dialog -->
    @if (_sessionToRevoke is not null)
    {
        <div class="modal-backdrop fade show"></div>
        <div class="modal d-block fade show" tabindex="-1">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header">
                        <h5 class="modal-title">Revoke Session</h5>
                        <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                    </div>
                    <div class="modal-body">
                        <p>Are you sure you want to revoke this session?</p>
                        <p class="mb-0">
                            <strong>@_sessionToRevoke.Device</strong> — @_sessionToRevoke.Location
                        </p>
                    </div>
                    <div class="modal-footer">
                        <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                        <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                            @if (_revoking)
                            {
                                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                            }
                            Revoke
                        </button>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public SecuritySettings Security { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback<(string CurrentPassword, string NewPassword)> OnChangePassword { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnRevokeSession { get; set; }

    private bool _passwordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _changingPassword;
    private string? _statusMessage;
    private bool _isError;

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    private async Task ChangePasswordAsync()
    {
        _statusMessage = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _statusMessage = "Please fill in all password fields.";
            _isError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _statusMessage = "New password and confirmation do not match.";
            _isError = true;
            return;
        }

        _changingPassword = true;
        try
        {
            await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
            _statusMessage = "Password updated successfully!";
            _isError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _passwordExpanded = false;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to change password: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        try
        {
            await OnRevokeSession.InvokeAsync(_sessionToRevoke.Id);
            _statusMessage = $"Session on {_sessionToRevoke.Device} has been revoked.";
            _isError = false;
            _sessionToRevoke = null;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to revoke session: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _revoking = false;
        }
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

